INSERT INTO public.sprites (name, rarity, image_url, description, element) VALUES
  ('炎尾狐',   'N',   '/images/sprites/N_001.webp',   '栖居于火山脚下的小型火精灵，尾巴上常年燃着细小的火焰。',                                         '火'),
  ('水晶鱼',   'N',   '/images/sprites/N_002.webp',   '透明如水晶的小鱼精，游过的水面会留下点点蓝光。',                                               '水'),
  ('嫩芽兔',   'N',   '/images/sprites/N_003.webp',   '耳朵上长着嫩绿色嫩芽的草系精灵，喜欢在森林边缘跳跃。',                                           '草'),
  ('闪电鼠',   'N',   '/images/sprites/N_004.webp',   '毛发蓬松、充满静电的小鼠精，激动时会放出微弱的电弧。',                                           '电'),
  ('幽灯萤',   'N',   '/images/sprites/N_005.webp',   '在废弃庭院中飞舞的萤火精灵，发出的光有时带着哭声。',                                             '幽灵'),
  ('霜爪猫',   'N',   '/images/sprites/N_006.webp',   '脚掌结着薄冰的小猫精，踩过的地面会留下冰晶脚印。',                                             '冰'),
  ('暗影蝙',   'N',   '/images/sprites/N_007.webp',   '只在月圆之夜现身的蝙蝠精，翅膀折叠时形如一片阴影。',                                             '暗'),
  ('石鳞蜥',   'N',   '/images/sprites/N_008.webp',   '鳞片坚硬如石头的蜥蜴精，遇到危险会蜷成一颗石球。',                                             '草'),
  ('红果松鼠', 'N',   '/images/sprites/N_009.webp',   '总是抱着火红果实的松鼠精，能从果实中提取微弱的火焰。',                                           '火'),
  ('泡泡蛙',   'N',   '/images/sprites/N_010.webp',   '会吐出五彩泡泡的青蛙精，泡泡破裂时散发清凉水雾。',                                             '水'),
  ('电纹甲虫', 'N',   '/images/sprites/N_011.webp',   '甲壳上布满放电纹路的甲虫精，被触碰时会给人轻微电击。',                                           '电'),
  ('雪绒羊',   'N',   '/images/sprites/N_012.webp',   '全身覆盖着雪白绒毛的小羊精，寒冬中不惧风雪悠然漫步。',                                           '冰'),
  ('苔藓熊',   'N',   '/images/sprites/N_013.webp',   '背上长满青苔的小熊精，常常被误认为是一块苔藓岩石。',                                             '草'),
  ('灰烬鸦',   'N',   '/images/sprites/N_014.webp',   '羽毛带着余烬气息的乌鸦精，停落之处往往留有焦黑痕迹。',                                           '火'),
  ('迷雾鱼',   'N',   '/images/sprites/N_015.webp',   '能制造浓雾隐匿自身的小鱼精，夜晚常在湖面上静静漂浮。',                                           '幽灵'),
  ('燃鬃狼',   'R',   '/images/sprites/R_001.webp',   '鬃毛如同燃烧火焰的狼精，嚎叫时能点燃方圆数米的干草。',                                           '火'),
  ('珊瑚鲨',   'R',   '/images/sprites/R_002.webp',   '背鳍长满珊瑚的鲨鱼精，能在礁石间以惊人的速度穿梭。',                                             '水'),
  ('雷羽鹰',   'R',   '/images/sprites/R_003.webp',   '每一片羽毛都带有电荷的猎鹰精，展翅时引来漫天雷云。',                                             '电'),
  ('幽魂树',   'R',   '/images/sprites/R_004.webp',   '外形如古树却能行走的幽灵精，树洞里藏着无数消散的灵魂。',                                           '幽灵'),
  ('冰晶鹿',   'R',   '/images/sprites/R_005.webp',   '鹿角由纯净冰晶构成的精灵，踏雪而行时无声无息。',                                               '冰'),
  ('藤蟒',     'R',   '/images/sprites/R_006.webp',   '身体盘绕着常青藤的巨蟒精，能控制植物将猎物缠缚。',                                             '草'),
  ('黑曜蝎',   'R',   '/images/sprites/R_007.webp',   '全身如黑曜石般漆黑的蝎子精，毒液能腐蚀光明。',                                                 '暗'),
  ('晨曦羽凤', 'R',   '/images/sprites/R_008.webp',   '沐浴晨光而生的凤鸟精，羽毛上常有金色光芒流动。',                                               '光'),
  ('熔岩巨犀', 'SR',  '/images/sprites/SR_001.webp',  '角上流淌熔岩的犀牛精灵，冲锋时大地为之颤抖，火石四溅。',                                           '火'),
  ('深渊章鱼', 'SR',  '/images/sprites/SR_002.webp',  '来自深海深渊的章鱼精，每条触手都蕴藏着不可思议的水压。',                                           '水'),
  ('冰魄女妖', 'SR',  '/images/sprites/SR_003.webp',  '以永恒寒冰凝结而成的女妖精灵，歌声能将万物冻结于瞬间。',                                           '冰'),
  ('雷霆神鹰', 'SR',  '/images/sprites/SR_004.webp',  '翼展如云的神鹰精，每一次振翅皆掀起惊天雷霆。',                                                 '电'),
  ('混沌龙皇', 'SSR', '/images/sprites/SSR_001.webp', '身上鳞片凝聚混沌之力的古龙精灵，传说其一声低吼可撼动天地秩序。',                                     '龙'),
  ('虚空冥后', 'SSR', '/images/sprites/SSR_002.webp', '统御暗影与虚空的冥界女王精灵，裙裾所过之处光明尽灭，万籁俱寂。',                                     '暗'),
  ('创世光神', 'UR',  '/images/sprites/UR_001.webp',  '传说中开辟世界之初便存在的神明精灵，其光辉能净化一切黑暗与混沌，被各族视为最高守护神祇。',               '光');
